CREATE TABLE IF NOT EXISTS user_message (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, messageid INT, type VARCHAR(50), message_type VARCHAR(50), islooked VARCHAR(10) DEFAULT '0');
CREATE TABLE IF NOT EXISTS renrenMapping (id INT AUTO_INCREMENT PRIMARY KEY, rr_id VARCHAR(100), userid INT, is_binding VARCHAR(10));
CREATE TABLE IF NOT EXISTS user_circle (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, circleid INT, checktimes INT);
CREATE TABLE IF NOT EXISTS notes_hidden (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, hiddenid INT);
CREATE TABLE IF NOT EXISTS common_cf (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, sid INT, sign VARCHAR(50), fnum INT, cnum INT);
CREATE TABLE IF NOT EXISTS looktimes (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, typeid INT, type VARCHAR(50));
CREATE TABLE IF NOT EXISTS friends (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, friendid INT, last_vistedtime DATETIME, at_times INT DEFAULT 0, isignore VARCHAR(10) DEFAULT '0', concerned VARCHAR(10) DEFAULT '0');
CREATE TABLE IF NOT EXISTS last_visited (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, visitedid INT, visitedtime DATETIME);
CREATE TABLE IF NOT EXISTS show_privacy_circle (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, circleid INT);
CREATE TABLE IF NOT EXISTS show_privacy_friends (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, friendid INT);
CREATE TABLE IF NOT EXISTS favor (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, typeid INT, type VARCHAR(50));
CREATE TABLE IF NOT EXISTS pm_hidden (id INT AUTO_INCREMENT PRIMARY KEY, pmid INT, userid INT);
CREATE TABLE IF NOT EXISTS share_succeed (id INT AUTO_INCREMENT PRIMARY KEY, typeid INT, type VARCHAR(50), userid INT, friendid INT, addtime DATETIME);
CREATE TABLE IF NOT EXISTS admin_message (id INT AUTO_INCREMENT PRIMARY KEY, a_messageid INT, type VARCHAR(50));
CREATE TABLE IF NOT EXISTS circle_message (id INT AUTO_INCREMENT PRIMARY KEY, c_messageid INT, circleid INT, type VARCHAR(50));
CREATE TABLE IF NOT EXISTS privateMessageHidden (id INT AUTO_INCREMENT PRIMARY KEY, privateMessageId INT, userid INT);
CREATE TABLE IF NOT EXISTS commentedHidden (id INT AUTO_INCREMENT PRIMARY KEY, commentedId INT, commentedType VARCHAR(50), userid INT);
CREATE TABLE IF NOT EXISTS shield (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, shieldid INT);
CREATE TABLE IF NOT EXISTS activity_sellbook_bookLookedTimes (id INT AUTO_INCREMENT PRIMARY KEY, userid INT, bookid INT);
CREATE TABLE IF NOT EXISTS goods_circle (id INT AUTO_INCREMENT PRIMARY KEY, goodsid INT, circleid INT);
CREATE TABLE IF NOT EXISTS needs_circle (id INT AUTO_INCREMENT PRIMARY KEY, needsid INT, circleid INT);
